import os
import shutil
from pathlib import Path
from flask import Flask, jsonify, send_file, request
from werkzeug.utils import secure_filename

app = Flask(__name__)

UPLOAD_DIR = Path("./uploads")
BASE_DIR = Path("./uploads").resolve()
FILE_MAP = {}  # server-side mapping of file IDs to actual paths

def validate_and_resolve_path(user_path):
    """Validate and resolve user path, ensuring it's within BASE_DIR"""
    try:
        # Use pathlib to canonicalize and resolve the path
        full_path = (BASE_DIR / user_path).resolve()
        # Ensure the resolved path is within the base directory
        if not full_path.is_relative_to(BASE_DIR):
            raise ValueError("Path traversal detected")
        return full_path
    except Exception:
        raise ValueError("Invalid path")

def get_file_id(file_path):
    """Generate a unique file ID for a given path"""
    return str(file_path.relative_to(BASE_DIR).hash) if hasattr(Path, 'hash') else str(hash(file_path))

@app.route('/files', methods=['GET'])
def list_directory():
    try:
        path = request.args.get('path', '')
        full_path = validate_and_resolve_path(path)
        
        if not full_path.exists():
            return jsonify({"error": "Path not found"}), 404
            
        if not full_path.is_dir():
            return jsonify({"error": "Path is not a directory"}), 400
            
        items = []
        for item in full_path.iterdir():
            items.append({
                "name": item.name,
                "is_dir": item.is_dir(),
                "size": item.stat().st_size if not item.is_dir() else 0
            })
            
        return jsonify({"items": items})
        
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

@app.route('/files/download', methods=['GET'])
def download_file():
    try:
        path = request.args.get('path', '')
        full_path = validate_and_resolve_path(path)
        
        if not full_path.exists():
            return jsonify({"error": "File not found"}), 404
            
        if full_path.is_dir():
            return jsonify({"error": "Cannot download directory"}), 400
            
        return send_file(full_path, as_attachment=True)
        
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

@app.route('/files/info', methods=['GET'])
def get_file_info():
    try:
        path = request.args.get('path', '')
        full_path = validate_and_resolve_path(path)
        
        if not full_path.exists():
            return jsonify({"error": "File not found"}), 404
            
        stat = full_path.stat()
        info = {
            "name": full_path.name,
            "size": stat.st_size,
            "is_dir": full_path.is_dir(),
            "created": stat.st_ctime,
            "modified": stat.st_mtime
        }
        
        return jsonify(info)
        
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

if __name__ == '__main__':
    UPLOAD_DIR.mkdir(exist_ok=True)
    app.run(debug=False)